export const ARTICLES_06: Article[] = [
  { id: 'ccyc-art-661', lawId: 'codigo-civil-comercial', number: '661', order: 661, title: "Legitimación", text: "Legitimación. El progenitor que falte a la prestación de alimentos puede ser demandado por: a) el otro progenitor en representación del hijo; b) el hijo con grado de madurez suficiente con asistencia letrada; c) subsidiariamente, cualquiera de los parientes o el Ministerio Público.", plainLanguageExplanation: "Establece el régimen de legitimación. El progenitor que falte a la prestación de alimentos puede ser demandado por: a) el otro progenitor en representación del hijo; b) el hijo con grado de madurez suficiente con asistencia letrada; c) subsidiariamente, cualquiera de los parientes o el Ministerio Público.", practicalEffects: ['En la práctica, este artículo rige legitimación. El progenitor que falte a la prestación de alimentos puede ser demandado por: a) el otro progenitor en representación del hijo; b) el hijo con grado d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legitimacinarticulo 661'], segments: [], amendments: [] },
  { id: 'ccyc-art-662', lawId: 'codigo-civil-comercial', number: '662', order: 662, title: "Hijo mayor de edad", text: "Hijo mayor de edad. El progenitor que convive con el hijo mayor de edad tiene legitimación para obtener la contribución del otro hasta que el hijo cumpla veintiún años. Puede iniciar el juicio alimentario o, en su caso, continuar el proceso promovido durante la minoría de edad del hijo para que el juez determine la cuota que corresponde al otro progenitor. Tiene derecho a cobrar y administrar las cuotas alimentarias devengadas. Las partes de común acuerdo, o el juez, a pedido de alguno de los progenitores o del hijo, pueden fijar una suma que el hijo debe percibir directamente del progenitor no conviviente. Tal suma, administrada por el hijo, está destinada a cubrir los desembolsos de su vida diaria, como esparcimiento, gastos con fines culturales o educativos, vestimenta u otros rubros que se estimen pertinentes.", plainLanguageExplanation: "Establece el régimen de hijo mayor de edad. El progenitor que convive con el hijo mayor de edad tiene legitimación para obtener la contribución del otro hasta que el hijo cumpla veintiún años.", practicalEffects: ['En la práctica, este artículo rige hijo mayor de edad. El progenitor que convive con el hijo mayor de edad tiene legitimación para obtener la contribución del otro hasta que el hijo cumpla veintiún años.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hijo', 'mayor', 'edad', 'articulo 662'], segments: [], amendments: [] },
  { id: 'ccyc-art-663', lawId: 'codigo-civil-comercial', number: '663', order: 663, title: "Hijo mayor que se capacita", text: "Hijo mayor que se capacita. La obligación de los progenitores de proveer recursos al hijo subsiste hasta que éste alcance la edad de veinticinco años, si la prosecución de estudios o preparación profesional de un arte u oficio, le impide proveerse de medios necesarios para sostenerse independientemente. Pueden ser solicitados por el hijo o por el progenitor con el cual convive; debe acreditarse la viabilidad del pedido.", plainLanguageExplanation: "Establece el régimen de hijo mayor que se capacita. La obligación de los progenitores de proveer recursos al hijo subsiste hasta que éste alcance la edad de veinticinco años, si la prosecución de estudios o preparación profesional de un arte u oficio, le impide proveerse de medios necesarios para sostenerse independientemente.", practicalEffects: ['En la práctica, este artículo rige hijo mayor que se capacita. La obligación de los progenitores de proveer recursos al hijo subsiste hasta que éste alcance la edad de veinticinco años, si la prosecución de estudi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hijo', 'mayor', 'capacita', 'articulo 663'], segments: [], amendments: [] },
  { id: 'ccyc-art-664', lawId: 'codigo-civil-comercial', number: '664', order: 664, title: "Hijo no reconocido", text: "Hijo no reconocido. El hijo extramatrimonial no reconocido tiene derecho a alimentos provisorios mediante la acreditación sumaria del vínculo invocado. Si la demanda se promueve antes que el juicio de filiación, en la resolución que determina alimentos provisorios el juez debe establecer un plazo para promover dicha acción, bajo apercibimiento de cesar la cuota fijada mientras esa carga esté incumplida.", plainLanguageExplanation: "Establece el régimen de hijo no reconocido. El hijo extramatrimonial no reconocido tiene derecho a alimentos provisorios mediante la acreditación sumaria del vínculo invocado.", practicalEffects: ['En la práctica, este artículo rige hijo no reconocido. El hijo extramatrimonial no reconocido tiene derecho a alimentos provisorios mediante la acreditación sumaria del vínculo invocado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hijo', 'reconocido', 'articulo 664'], segments: [], amendments: [] },
  { id: 'ccyc-art-665', lawId: 'codigo-civil-comercial', number: '665', order: 665, title: "Mujer embarazada", text: "Mujer embarazada. La mujer embarazada tiene derecho a reclamar alimentos al progenitor presunto con la prueba sumaria de la filiación alegada.", plainLanguageExplanation: "Establece el régimen de mujer embarazada. La mujer embarazada tiene derecho a reclamar alimentos al progenitor presunto con la prueba sumaria de la filiación alegada.", practicalEffects: ['En la práctica, este artículo rige mujer embarazada. La mujer embarazada tiene derecho a reclamar alimentos al progenitor presunto con la prueba sumaria de la filiación alegada.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mujer', 'embarazada', 'articulo 665'], segments: [], amendments: [] },
  { id: 'ccyc-art-666', lawId: 'codigo-civil-comercial', number: '666', order: 666, title: "Cuidado personal compartido", text: "Cuidado personal compartido. En el caso de cuidado personal compartido, si ambos progenitores cuentan con recursos equivalentes, cada uno debe hacerse cargo de la manutención cuando el hijo permanece bajo su cuidado; si los recursos de los progenitores no son equivalentes, aquel que cuenta con mayores ingresos debe pasar una cuota alimentaria al otro para que el hijo goce del mismo nivel de vida en ambos hogares. Los gastos comunes deben ser solventados por ambos progenitores, de conformidad con lo dispuesto en el artículo 658.", plainLanguageExplanation: "Establece el régimen de cuidado personal compartido. En el caso de cuidado personal compartido, si ambos progenitores cuentan con recursos equivalentes, cada uno debe hacerse cargo de la manutención cuando el hijo permanece bajo su cuidado; si los recursos de los progenitores no son equivalentes, aquel que cuenta con mayores ingres", practicalEffects: ['En la práctica, este artículo rige cuidado personal compartido. En el caso de cuidado personal compartido, si ambos progenitores cuentan con recursos equivalentes, cada uno debe hacerse cargo de la manutención cuan'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cuidado', 'personal', 'compartido', 'articulo 666'], segments: [], amendments: [] },
  { id: 'ccyc-art-667', lawId: 'codigo-civil-comercial', number: '667', order: 667, title: "Hijo fuera del país o alejado de sus progenitores", text: "Hijo fuera del país o alejado de sus progenitores. El hijo que no convive con sus progenitores, que se encuentra en un país extranjero o en un lugar alejado dentro de la República, y tenga necesidad de recursos para su alimentación u otros rubros urgentes, puede ser autorizado por el juez del lugar o por la representación diplomática de la República, según el caso, para contraer deudas que satisfagan sus necesidades. Si es adolescente no necesita autorización alguna; sólo el asentimiento del adulto responsable, de conformidad con la legislación aplicable.", plainLanguageExplanation: "Establece el régimen de hijo fuera del país o alejado de sus progenitores. El hijo que no convive con sus progenitores, que se encuentra en un país extranjero o en un lugar alejado dentro de la República, y tenga necesidad de recursos para su alimentación u otros rubros urgentes, puede ser autorizado por el juez del lugar o por la representación diplomá", practicalEffects: ['En la práctica, este artículo rige hijo fuera del país o alejado de sus progenitores. El hijo que no convive con sus progenitores, que se encuentra en un país extranjero o en un lugar alejado dentro de la República, y tenga necesidad de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hijo', 'fuera', 'pas', 'alejado', 'progenitores', 'articulo 667'], segments: [], amendments: [] },
  { id: 'ccyc-art-668', lawId: 'codigo-civil-comercial', number: '668', order: 668, title: "Reclamo a ascendientes", text: "Reclamo a ascendientes. Los alimentos a los ascendientes pueden ser reclamados en el mismo proceso en que se demanda a los progenitores o en proceso diverso; además de lo previsto en el título del parentesco, debe acreditarse verosímilmente las dificultades del actor para percibir los alimentos del progenitor obligado.", plainLanguageExplanation: "Establece el régimen de reclamo a ascendientes. Los alimentos a los ascendientes pueden ser reclamados en el mismo proceso en que se demanda a los progenitores o en proceso diverso; además de lo previsto en el título del parentesco, debe acreditarse verosímilmente las dificultades del actor para percibir los alimentos del prog", practicalEffects: ['En la práctica, este artículo rige reclamo a ascendientes. Los alimentos a los ascendientes pueden ser reclamados en el mismo proceso en que se demanda a los progenitores o en proceso diverso; además de lo pre'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reclamo', 'ascendientes', 'articulo 668'], segments: [], amendments: [] },
  { id: 'ccyc-art-669', lawId: 'codigo-civil-comercial', number: '669', order: 669, title: "Alimentos impagos", text: "Alimentos impagos. Los alimentos se deben desde el día de la demanda o desde el día de la interpelación del obligado por medio fehaciente, siempre que se interponga la demanda dentro de los seis meses de la interpelación. Por el período anterior, el progenitor que asumió el cuidado del hijo tiene derecho al reembolso de lo gastado en la parte que corresponde al progenitor no conviviente.", plainLanguageExplanation: "Establece el régimen de alimentos impagos. Los alimentos se deben desde el día de la demanda o desde el día de la interpelación del obligado por medio fehaciente, siempre que se interponga la demanda dentro de los seis meses de la interpelación.", practicalEffects: ['En la práctica, este artículo rige alimentos impagos. Los alimentos se deben desde el día de la demanda o desde el día de la interpelación del obligado por medio fehaciente, siempre que se interponga la d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['alimentos', 'impagos', 'articulo 669'], segments: [], amendments: [] },
  { id: 'ccyc-art-670', lawId: 'codigo-civil-comercial', number: '670', order: 670, title: "Medidas ante el incumplimiento", text: "Medidas ante el incumplimiento. Las disposiciones de este Código relativas al incumplimiento de los alimentos entre parientes son aplicables a los alimentos entre padres e hijos. CAPITULO 6 Deberes de los hijos", plainLanguageExplanation: "Establece el régimen de medidas ante el incumplimiento. Las disposiciones de este Código relativas al incumplimiento de los alimentos entre parientes son aplicables a los alimentos entre padres e hijos.", practicalEffects: ['En la práctica, este artículo rige medidas ante el incumplimiento. Las disposiciones de este Código relativas al incumplimiento de los alimentos entre parientes son aplicables a los alimentos entre padres e hijos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medidas', 'ante', 'incumplimiento', 'articulo 670'], segments: [], amendments: [] },
  { id: 'ccyc-art-671', lawId: 'codigo-civil-comercial', number: '671', order: 671, title: "Enumeración", text: "Enumeración. Son deberes de los hijos: a) respetar a sus progenitores; b) cumplir con las decisiones de los progenitores que no sean contrarias a su interés superior; c) prestar a los progenitores colaboración propia de su edad y desarrollo y cuidar de ellos u otros ascendientes en todas las circunstancias de la vida en que su ayuda sea necesaria. CAPITULO 7 Deberes y derechos de los progenitores e hijos afines", plainLanguageExplanation: "Establece el régimen de enumeración. Son deberes de los hijos: a) respetar a sus progenitores; b) cumplir con las decisiones de los progenitores que no sean contrarias a su interés superior; c) prestar a los progenitores colaboración propia de su edad y desarrollo y cuidar de ellos u otros ascendientes en todas las", practicalEffects: ['En la práctica, este artículo rige enumeración. Son deberes de los hijos: a) respetar a sus progenitores; b) cumplir con las decisiones de los progenitores que no sean contrarias a su interés superi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['enumeracinarticulo 671'], segments: [], amendments: [] },
  { id: 'ccyc-art-672', lawId: 'codigo-civil-comercial', number: '672', order: 672, title: "Progenitor afín", text: "Progenitor afín. Se denomina progenitor afín al cónyuge o conviviente que vive con quien tiene a su cargo el cuidado personal del niño o adolescente.", plainLanguageExplanation: "Establece el régimen de progenitor afín. Se denomina progenitor afín al cónyuge o conviviente que vive con quien tiene a su cargo el cuidado personal del niño o adolescente.", practicalEffects: ['En la práctica, este artículo rige progenitor afín. Se denomina progenitor afín al cónyuge o conviviente que vive con quien tiene a su cargo el cuidado personal del niño o adolescente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['progenitor', 'afn', 'articulo 672'], segments: [], amendments: [] },
  { id: 'ccyc-art-673', lawId: 'codigo-civil-comercial', number: '673', order: 673, title: "Deberes del progenitor afín", text: "Deberes del progenitor afín. El cónyuge o conviviente de un progenitor debe cooperar en la crianza y educación de los hijos del otro, realizar los actos cotidianos relativos a su formación en el ámbito doméstico y adoptar decisiones ante situaciones de urgencia. En caso de desacuerdo entre el progenitor y su cónyuge o conviviente prevalece el criterio del progenitor. Esta colaboración no afecta los derechos de los titulares de la responsabilidad parental.", plainLanguageExplanation: "Establece el régimen de deberes del progenitor afín. El cónyuge o conviviente de un progenitor debe cooperar en la crianza y educación de los hijos del otro, realizar los actos cotidianos relativos a su formación en el ámbito doméstico y adoptar decisiones ante situaciones de urgencia.", practicalEffects: ['En la práctica, este artículo rige deberes del progenitor afín. El cónyuge o conviviente de un progenitor debe cooperar en la crianza y educación de los hijos del otro, realizar los actos cotidianos relativos a su'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deberes', 'progenitor', 'afn', 'articulo 673'], segments: [], amendments: [] },
  { id: 'ccyc-art-674', lawId: 'codigo-civil-comercial', number: '674', order: 674, title: "Delegación en el progenitor afín", text: "Delegación en el progenitor afín. El progenitor a cargo del hijo puede delegar a su cónyuge o conviviente el ejercicio de la responsabilidad parental cuando no estuviera en condiciones de cumplir la función en forma plena por razones de viaje, enfermedad o incapacidad transitoria, y siempre que exista imposibilidad para su desempeño por parte del otro progenitor, o no fuera conveniente que este último asuma su ejercicio. Esta delegación requiere la homologación judicial, excepto que el otro progenitor exprese su acuerdo de modo fehaciente.", plainLanguageExplanation: "Establece el régimen de delegación en el progenitor afín. El progenitor a cargo del hijo puede delegar a su cónyuge o conviviente el ejercicio de la responsabilidad parental cuando no estuviera en condiciones de cumplir la función en forma plena por razones de viaje, enfermedad o incapacidad transitoria, y siempre que exista imposibilid", practicalEffects: ['En la práctica, este artículo rige delegación en el progenitor afín. El progenitor a cargo del hijo puede delegar a su cónyuge o conviviente el ejercicio de la responsabilidad parental cuando no estuviera en condiciones'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['delegacin', 'progenitor', 'afn', 'articulo 674'], segments: [], amendments: [] },
  { id: 'ccyc-art-675', lawId: 'codigo-civil-comercial', number: '675', order: 675, title: "Ejercicio conjunto con el progenitor afín", text: "Ejercicio conjunto con el progenitor afín. En caso de muerte, ausencia o incapacidad del progenitor, el otro progenitor puede asumir dicho ejercicio conjuntamente con su cónyuge o conviviente. Este acuerdo entre el progenitor en ejercicio de la responsabilidad parental y su cónyuge o conviviente debe ser homologado judicialmente. En caso de conflicto prima la opinión del progenitor. Este ejercicio se extingue con la ruptura del matrimonio o de la unión convivencial. También se extingue con la recuperación de la capacidad plena del progenitor que no estaba en ejercicio de la responsabilidad parental.", plainLanguageExplanation: "Establece el régimen de ejercicio conjunto con el progenitor afín. En caso de muerte, ausencia o incapacidad del progenitor, el otro progenitor puede asumir dicho ejercicio conjuntamente con su cónyuge o conviviente.", practicalEffects: ['En la práctica, este artículo rige ejercicio conjunto con el progenitor afín. En caso de muerte, ausencia o incapacidad del progenitor, el otro progenitor puede asumir dicho ejercicio conjuntamente con su cónyuge o conviviente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ejercicio', 'conjunto', 'progenitor', 'afn', 'articulo 675'], segments: [], amendments: [] },
  { id: 'ccyc-art-676', lawId: 'codigo-civil-comercial', number: '676', order: 676, title: "Alimentos", text: "Alimentos. La obligación alimentaria del cónyuge o conviviente respecto de los hijos del otro, tiene carácter subsidiario. Cesa este deber en los casos de disolución del vínculo conyugal o ruptura de la convivencia. Sin embargo, si el cambio de situación puede ocasionar un grave daño al niño o adolescente y el cónyuge o conviviente asumió durante la vida en común el sustento del hijo del otro, puede fijarse una cuota asistencial a su cargo con carácter transitorio, cuya duración debe definir el juez de acuerdo a las condiciones de fortuna del obligado, las necesidades del alimentado y el tiempo de la convivencia. CAPITULO 8 Representación, disposición y administración de los bienes del hijo menor de edad", plainLanguageExplanation: "Establece el régimen de alimentos. La obligación alimentaria del cónyuge o conviviente respecto de los hijos del otro, tiene carácter subsidiario.", practicalEffects: ['En la práctica, este artículo rige alimentos. La obligación alimentaria del cónyuge o conviviente respecto de los hijos del otro, tiene carácter subsidiario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['alimentosarticulo 676'], segments: [], amendments: [] },
  { id: 'ccyc-art-677', lawId: 'codigo-civil-comercial', number: '677', order: 677, title: "Representación", text: "Representación. Los progenitores pueden estar en juicio por su hijo como actores o demandados. Se presume que el hijo adolescente cuenta con suficiente autonomía para intervenir en un proceso conjuntamente con los progenitores, o de manera autónoma con asistencia letrada.", plainLanguageExplanation: "Establece el régimen de representación. Los progenitores pueden estar en juicio por su hijo como actores o demandados.", practicalEffects: ['En la práctica, este artículo rige representación. Los progenitores pueden estar en juicio por su hijo como actores o demandados.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['representacinarticulo 677'], segments: [], amendments: [] },
  { id: 'ccyc-art-678', lawId: 'codigo-civil-comercial', number: '678', order: 678, title: "Oposición al juicio", text: "Oposición al juicio. Si uno o ambos progenitores se oponen a que el hijo adolescente inicie una acción civil contra un tercero, el juez puede autorizarlo a intervenir en el proceso con la debida asistencia letrada, previa audiencia del oponente y del Ministerio Público.", plainLanguageExplanation: "Establece el régimen de oposición al juicio. Si uno o ambos progenitores se oponen a que el hijo adolescente inicie una acción civil contra un tercero, el juez puede autorizarlo a intervenir en el proceso con la debida asistencia letrada, previa audiencia del oponente y del Ministerio Público.", practicalEffects: ['En la práctica, este artículo rige oposición al juicio. Si uno o ambos progenitores se oponen a que el hijo adolescente inicie una acción civil contra un tercero, el juez puede autorizarlo a intervenir en e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oposicin', 'juicio', 'articulo 678'], segments: [], amendments: [] },
  { id: 'ccyc-art-679', lawId: 'codigo-civil-comercial', number: '679', order: 679, title: "Juicio contra los progenitores", text: "Juicio contra los progenitores. El hijo menor de edad puede reclamar a sus progenitores por sus propios intereses sin previa autorización judicial, si cuenta con la edad y grado de madurez suficiente y asistencia letrada.", plainLanguageExplanation: "Establece el régimen de juicio contra los progenitores. El hijo menor de edad puede reclamar a sus progenitores por sus propios intereses sin previa autorización judicial, si cuenta con la edad y grado de madurez suficiente y asistencia letrada.", practicalEffects: ['En la práctica, este artículo rige juicio contra los progenitores. El hijo menor de edad puede reclamar a sus progenitores por sus propios intereses sin previa autorización judicial, si cuenta con la edad y grado de m'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juicio', 'contra', 'progenitores', 'articulo 679'], segments: [], amendments: [] },
  { id: 'ccyc-art-680', lawId: 'codigo-civil-comercial', number: '680', order: 680, title: "Hijo adolescente en juicio", text: "Hijo adolescente en juicio. El hijo adolescente no precisa autorización de sus progenitores para estar en juicio cuando sea acusado criminalmente, ni para reconocer hijos.", plainLanguageExplanation: "Establece el régimen de hijo adolescente en juicio. El hijo adolescente no precisa autorización de sus progenitores para estar en juicio cuando sea acusado criminalmente, ni para reconocer hijos.", practicalEffects: ['En la práctica, este artículo rige hijo adolescente en juicio. El hijo adolescente no precisa autorización de sus progenitores para estar en juicio cuando sea acusado criminalmente, ni para reconocer hijos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['hijo', 'adolescente', 'juicio', 'articulo 680'], segments: [], amendments: [] },
  { id: 'ccyc-art-681', lawId: 'codigo-civil-comercial', number: '681', order: 681, title: "Contratos por servicios del hijo menor de dieciséis años", text: "Contratos por servicios del hijo menor de dieciséis años. El hijo menor de dieciséis años no puede ejercer oficio, profesión o industria, ni obligar a su persona de otra manera sin autorización de sus progenitores; en todo caso, debe cumplirse con las disposiciones de este Código y de leyes especiales.", plainLanguageExplanation: "Establece el régimen de contratos por servicios del hijo menor de dieciséis años. El hijo menor de dieciséis años no puede ejercer oficio, profesión o industria, ni obligar a su persona de otra manera sin autorización de sus progenitores; en todo caso, debe cumplirse con las disposiciones de este Código y de leyes especiales.", practicalEffects: ['En la práctica, este artículo rige contratos por servicios del hijo menor de dieciséis años. El hijo menor de dieciséis años no puede ejercer oficio, profesión o industria, ni obligar a su persona de otra manera sin autorización de sus progeni'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'servicios', 'hijo', 'menor', 'diecisis', 'aos', 'articulo 681'], segments: [], amendments: [] },
  { id: 'ccyc-art-682', lawId: 'codigo-civil-comercial', number: '682', order: 682, title: "Contratos por servicios del hijo mayor de dieciséis años", text: "Contratos por servicios del hijo mayor de dieciséis años. Los progenitores no pueden hacer contratos por servicios a prestar por su hijo adolescente o para que aprenda algún oficio sin su consentimiento y de conformidad con los requisitos previstos en leyes especiales.", plainLanguageExplanation: "Establece el régimen de contratos por servicios del hijo mayor de dieciséis años. Los progenitores no pueden hacer contratos por servicios a prestar por su hijo adolescente o para que aprenda algún oficio sin su consentimiento y de conformidad con los requisitos previstos en leyes especiales.", practicalEffects: ['En la práctica, este artículo rige contratos por servicios del hijo mayor de dieciséis años. Los progenitores no pueden hacer contratos por servicios a prestar por su hijo adolescente o para que aprenda algún oficio sin su consentimiento y de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'servicios', 'hijo', 'mayor', 'diecisis', 'aos', 'articulo 682'], segments: [], amendments: [] },
  { id: 'ccyc-art-683', lawId: 'codigo-civil-comercial', number: '683', order: 683, title: "Presunción de autorización para hijo mayor de dieciséis años", text: "Presunción de autorización para hijo mayor de dieciséis años. Se presume que el hijo mayor de dieciséis años que ejerce algún empleo, profesión o industria, está autorizado por sus progenitores para todos los actos y contratos concernientes al empleo, profesión o industria. En todo caso debe cumplirse con las disposiciones de este Código y con la normativa especial referida al trabajo infantil. Los derechos y obligaciones que nacen de estos actos recaen únicamente sobre los bienes cuya administración está a cargo del propio hijo.", plainLanguageExplanation: "Establece el régimen de presunción de autorización para hijo mayor de dieciséis años. Se presume que el hijo mayor de dieciséis años que ejerce algún empleo, profesión o industria, está autorizado por sus progenitores para todos los actos y contratos concernientes al empleo, profesión o industria.", practicalEffects: ['En la práctica, este artículo rige presunción de autorización para hijo mayor de dieciséis años. Se presume que el hijo mayor de dieciséis años que ejerce algún empleo, profesión o industria, está autorizado por sus progenitores para todos los act'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presuncin', 'autorizacin', 'para', 'hijo', 'mayor', 'diecisis', 'aos', 'articulo 683'], segments: [], amendments: [] },
  { id: 'ccyc-art-684', lawId: 'codigo-civil-comercial', number: '684', order: 684, title: "Contratos de escasa cuantía", text: "Contratos de escasa cuantía. Los contratos de escasa cuantía de la vida cotidiana celebrados por el hijo, se presumen realizados con la conformidad de los progenitores.", plainLanguageExplanation: "Establece el régimen de contratos de escasa cuantía. Los contratos de escasa cuantía de la vida cotidiana celebrados por el hijo, se presumen realizados con la conformidad de los progenitores.", practicalEffects: ['En la práctica, este artículo rige contratos de escasa cuantía. Los contratos de escasa cuantía de la vida cotidiana celebrados por el hijo, se presumen realizados con la conformidad de los progenitores.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'escasa', 'cuanta', 'articulo 684'], segments: [], amendments: [] },
  { id: 'ccyc-art-685', lawId: 'codigo-civil-comercial', number: '685', order: 685, title: "Administración de los bienes", text: "Administración de los bienes. La administración de los bienes del hijo es ejercida en común por los progenitores cuando ambos estén en ejercicio de la responsabilidad parental. Los actos conservatorios pueden ser otorgados indistintamente por cualquiera de los progenitores. Esta disposición se aplica con independencia de que el cuidado sea unipersonal o compartido.", plainLanguageExplanation: "Establece el régimen de administración de los bienes. La administración de los bienes del hijo es ejercida en común por los progenitores cuando ambos estén en ejercicio de la responsabilidad parental.", practicalEffects: ['En la práctica, este artículo rige administración de los bienes. La administración de los bienes del hijo es ejercida en común por los progenitores cuando ambos estén en ejercicio de la responsabilidad parental.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['administracin', 'bienes', 'articulo 685'], segments: [], amendments: [] },
  { id: 'ccyc-art-686', lawId: 'codigo-civil-comercial', number: '686', order: 686, title: "Excepciones a la administración", text: "Excepciones a la administración. Se exceptúan los siguientes bienes de la administración: a) los adquiridos por el hijo mediante trabajo, empleo, profesión o industria, que son administrados por éste, aunque conviva con sus progenitores; b) los heredados por el hijo por indignidad de sus progenitores; c) los adquiridos por herencia, legado o donación, cuando el donante o testador haya excluido expresamente la administración de los progenitores.", plainLanguageExplanation: "Establece el régimen de excepciones a la administración. Se exceptúan los siguientes bienes de la administración: a) los adquiridos por el hijo mediante trabajo, empleo, profesión o industria, que son administrados por éste, aunque conviva con sus progenitores; b) los heredados por el hijo por indignidad de sus progenitores; c) los adq", practicalEffects: ['En la práctica, este artículo rige excepciones a la administración. Se exceptúan los siguientes bienes de la administración: a) los adquiridos por el hijo mediante trabajo, empleo, profesión o industria, que son admini'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['excepciones', 'administracin', 'articulo 686'], segments: [], amendments: [] },
  { id: 'ccyc-art-687', lawId: 'codigo-civil-comercial', number: '687', order: 687, title: "Designación voluntaria de administrador", text: "Designación voluntaria de administrador. Los progenitores pueden acordar que uno de ellos administre los bienes del hijo; en ese caso, el progenitor administrador necesita el consentimiento expreso del otro para todos los actos que requieran también autorización judicial.", plainLanguageExplanation: "Establece el régimen de designación voluntaria de administrador. Los progenitores pueden acordar que uno de ellos administre los bienes del hijo; en ese caso, el progenitor administrador necesita el consentimiento expreso del otro para todos los actos que requieran también autorización judicial.", practicalEffects: ['En la práctica, este artículo rige designación voluntaria de administrador. Los progenitores pueden acordar que uno de ellos administre los bienes del hijo; en ese caso, el progenitor administrador necesita el consentimiento e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['designacin', 'voluntaria', 'administrador', 'articulo 687'], segments: [], amendments: [] },
  { id: 'ccyc-art-688', lawId: 'codigo-civil-comercial', number: '688', order: 688, title: "Desacuerdos", text: "Desacuerdos. En caso de graves o persistentes desacuerdos sobre la administración de los bienes, cualquiera de los progenitores puede recurrir al juez para que designe a uno de ellos o, en su defecto, a un tercero idóneo para ejercer la función.", plainLanguageExplanation: "Establece el régimen de desacuerdos. En caso de graves o persistentes desacuerdos sobre la administración de los bienes, cualquiera de los progenitores puede recurrir al juez para que designe a uno de ellos o, en su defecto, a un tercero idóneo para ejercer la función.", practicalEffects: ['En la práctica, este artículo rige desacuerdos. En caso de graves o persistentes desacuerdos sobre la administración de los bienes, cualquiera de los progenitores puede recurrir al juez para que des'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['desacuerdosarticulo 688'], segments: [], amendments: [] },
  { id: 'ccyc-art-689', lawId: 'codigo-civil-comercial', number: '689', order: 689, title: "Contratos prohibidos", text: "Contratos prohibidos. Los progenitores no pueden hacer contrato alguno con el hijo que está bajo su responsabilidad, excepto lo dispuesto para las donaciones sin cargo previstas en el artículo 1549. No pueden, ni aun con autorización judicial, comprar por sí ni por persona interpuesta, bienes de su hijo ni constituirse en cesionarios de créditos, derechos o acciones contra su hijo; ni hacer partición privada con su hijo de la herencia del progenitor prefallecido, ni de la herencia en que sean con él coherederos o colegatarios; ni obligar a su hijo como fiadores de ellos o de terceros.", plainLanguageExplanation: "Establece el régimen de contratos prohibidos. Los progenitores no pueden hacer contrato alguno con el hijo que está bajo su responsabilidad, excepto lo dispuesto para las donaciones sin cargo previstas en el artículo 1549.", practicalEffects: ['En la práctica, este artículo rige contratos prohibidos. Los progenitores no pueden hacer contrato alguno con el hijo que está bajo su responsabilidad, excepto lo dispuesto para las donaciones sin cargo previstas en el artículo 1549.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'prohibidos', 'articulo 689'], segments: [], amendments: [] },
  { id: 'ccyc-art-690', lawId: 'codigo-civil-comercial', number: '690', order: 690, title: "Contratos con terceros", text: "Contratos con terceros. Los progenitores pueden celebrar contratos con terceros en nombre de su hijo en los límites de su administración. Deben informar al hijo que cuenta con la edad y grado de madurez suficiente.", plainLanguageExplanation: "Establece el régimen de contratos con terceros. Los progenitores pueden celebrar contratos con terceros en nombre de su hijo en los límites de su administración.", practicalEffects: ['En la práctica, este artículo rige contratos con terceros. Los progenitores pueden celebrar contratos con terceros en nombre de su hijo en los límites de su administración.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'terceros', 'articulo 690'], segments: [], amendments: [] },
  { id: 'ccyc-art-691', lawId: 'codigo-civil-comercial', number: '691', order: 691, title: "Contratos de locación", text: "Contratos de locación. La locación de bienes del hijo realizada por los progenitores lleva implícita la condición de extinguirse cuando la responsabilidad parental concluya.", plainLanguageExplanation: "Establece el régimen de contratos de locación. La locación de bienes del hijo realizada por los progenitores lleva implícita la condición de extinguirse cuando la responsabilidad parental concluya.", practicalEffects: ['En la práctica, este artículo rige contratos de locación. La locación de bienes del hijo realizada por los progenitores lleva implícita la condición de extinguirse cuando la responsabilidad parental concluya.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['contratos', 'locacin', 'articulo 691'], segments: [], amendments: [] },
  { id: 'ccyc-art-692', lawId: 'codigo-civil-comercial', number: '692', order: 692, title: "Actos que necesitan autorización judicial", text: "Actos que necesitan autorización judicial. Se necesita autorización judicial para disponer los bienes del hijo. Los actos realizados sin autorización pueden ser declarados nulos si perjudican al hijo.", plainLanguageExplanation: "Establece el régimen de actos que necesitan autorización judicial. Se necesita autorización judicial para disponer los bienes del hijo.", practicalEffects: ['En la práctica, este artículo rige actos que necesitan autorización judicial. Se necesita autorización judicial para disponer los bienes del hijo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'necesitan', 'autorizacin', 'judicial', 'articulo 692'], segments: [], amendments: [] },
  { id: 'ccyc-art-693', lawId: 'codigo-civil-comercial', number: '693', order: 693, title: "Obligación de realizar inventario", text: "Obligación de realizar inventario. En los tres meses subsiguientes al fallecimiento de uno de los progenitores, el sobreviviente debe hacer inventario judicial de los bienes de los cónyuges o de los convivientes, y determinarse en él los bienes que correspondan al hijo, bajo pena de una multa pecuniaria a ser fijada por el juez a solicitud de parte interesada.", plainLanguageExplanation: "Establece el régimen de obligación de realizar inventario. En los tres meses subsiguientes al fallecimiento de uno de los progenitores, el sobreviviente debe hacer inventario judicial de los bienes de los cónyuges o de los convivientes, y determinarse en él los bienes que correspondan al hijo, bajo pena de una multa pecuniaria a ser fija", practicalEffects: ['En la práctica, este artículo rige obligación de realizar inventario. En los tres meses subsiguientes al fallecimiento de uno de los progenitores, el sobreviviente debe hacer inventario judicial de los bienes de los cóny'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligacin', 'realizar', 'inventario', 'articulo 693'], segments: [], amendments: [] },
  { id: 'ccyc-art-694', lawId: 'codigo-civil-comercial', number: '694', order: 694, title: "Pérdida de la administración", text: "Pérdida de la administración. Los progenitores pierden la administración de los bienes del hijo cuando ella sea ruinosa, o se pruebe su ineptitud para administrarlos. El juez puede declarar la pérdida de la administración en los casos de concurso o quiebra del progenitor que administra los bienes del hijo.", plainLanguageExplanation: "Establece el régimen de pérdida de la administración. Los progenitores pierden la administración de los bienes del hijo cuando ella sea ruinosa, o se pruebe su ineptitud para administrarlos.", practicalEffects: ['En la práctica, este artículo rige pérdida de la administración. Los progenitores pierden la administración de los bienes del hijo cuando ella sea ruinosa, o se pruebe su ineptitud para administrarlos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prdida', 'administracin', 'articulo 694'], segments: [], amendments: [] },
  { id: 'ccyc-art-695', lawId: 'codigo-civil-comercial', number: '695', order: 695, title: "Administración y privación de responsabilidad parental", text: "Administración y privación de responsabilidad parental. Los progenitores pierden la administración de los bienes del hijo cuando son privados de la responsabilidad parental.", plainLanguageExplanation: "Establece el régimen de administración y privación de responsabilidad parental. Los progenitores pierden la administración de los bienes del hijo cuando son privados de la responsabilidad parental.", practicalEffects: ['En la práctica, este artículo rige administración y privación de responsabilidad parental. Los progenitores pierden la administración de los bienes del hijo cuando son privados de la responsabilidad parental.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['administracin', 'privacin', 'responsabilidad', 'parental', 'articulo 695'], segments: [], amendments: [] },
  { id: 'ccyc-art-696', lawId: 'codigo-civil-comercial', number: '696', order: 696, title: "Remoción de la administración", text: "Remoción de la administración. Removido uno de los progenitores de la administración de los bienes, ésta corresponde al otro. Si ambos son removidos, el juez debe nombrar un tutor especial.", plainLanguageExplanation: "Establece el régimen de remoción de la administración. Removido uno de los progenitores de la administración de los bienes, ésta corresponde al otro.", practicalEffects: ['En la práctica, este artículo rige remoción de la administración. Removido uno de los progenitores de la administración de los bienes, ésta corresponde al otro.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remocin', 'administracin', 'articulo 696'], segments: [], amendments: [] },
  { id: 'ccyc-art-697', lawId: 'codigo-civil-comercial', number: '697', order: 697, title: "Rentas", text: "Rentas. Las rentas de los bienes del hijo corresponden a éste. Los progenitores están obligados a preservarlas cuidando de que no se confundan con sus propios bienes. Sólo pueden disponer de las rentas de los bienes del hijo con autorización judicial y por razones fundadas, en beneficio de los hijos. Los progenitores pueden rendir cuentas a pedido del hijo, presumiéndose su madurez.", plainLanguageExplanation: "Establece el régimen de rentas. Las rentas de los bienes del hijo corresponden a éste.", practicalEffects: ['En la práctica, este artículo rige rentas. Las rentas de los bienes del hijo corresponden a éste.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rentasarticulo 697'], segments: [], amendments: [] },
  { id: 'ccyc-art-698', lawId: 'codigo-civil-comercial', number: '698', order: 698, title: "Utilización de las rentas", text: "Utilización de las rentas. Los progenitores pueden utilizar las rentas de los bienes del hijo sin autorización judicial pero con la obligación de rendir cuentas, cuando se trata de solventar los siguientes gastos: a) de subsistencia y educación del hijo cuando los progenitores no pueden asumir esta responsabilidad a su cargo por incapacidad o dificultad económica; b) de enfermedad del hijo y de la persona que haya instituido heredero al hijo; c) de conservación del capital, devengado durante la minoridad del hijo. CAPITULO 9 Extinción, privación, suspensión y rehabilitación de la responsabilidad parental", plainLanguageExplanation: "Establece el régimen de utilización de las rentas. Los progenitores pueden utilizar las rentas de los bienes del hijo sin autorización judicial pero con la obligación de rendir cuentas, cuando se trata de solventar los siguientes gastos: a) de subsistencia y educación del hijo cuando los progenitores no pueden asumir esta respons", practicalEffects: ['En la práctica, este artículo rige utilización de las rentas. Los progenitores pueden utilizar las rentas de los bienes del hijo sin autorización judicial pero con la obligación de rendir cuentas, cuando se trata'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['utilizacin', 'rentas', 'articulo 698'], segments: [], amendments: [] },
  { id: 'ccyc-art-699', lawId: 'codigo-civil-comercial', number: '699', order: 699, title: "Extinción de la titularidad", text: "Extinción de la titularidad. La titularidad de la responsabilidad parental se extingue por: a) muerte del progenitor o del hijo; b) profesión del progenitor en instituto monástico; c) alcanzar el hijo la mayoría de edad; d) emancipación, excepto lo dispuesto en el artículo 644; e) adopción del hijo por un tercero, sin perjuicio de la posibilidad de que se la restituya en caso de revocación y nulidad de la adopción; la extinción no se produce cuando se adopta el hijo del cónyuge o del conviviente.", plainLanguageExplanation: "Establece el régimen de extinción de la titularidad. La titularidad de la responsabilidad parental se extingue por: a) muerte del progenitor o del hijo; b) profesión del progenitor en instituto monástico; c) alcanzar el hijo la mayoría de edad; d) emancipación, excepto lo dispuesto en el artículo 644; e) adopción del hijo por un te", practicalEffects: ['En la práctica, este artículo rige extinción de la titularidad. La titularidad de la responsabilidad parental se extingue por: a) muerte del progenitor o del hijo; b) profesión del progenitor en instituto monástico'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extincin', 'titularidad', 'articulo 699'], segments: [], amendments: [] },
  { id: 'ccyc-art-700', lawId: 'codigo-civil-comercial', number: '700', order: 700, title: "Privación", text: "Privación. Cualquiera de los progenitores queda privado de la responsabilidad parental por: a) ser condenado como autor, coautor, instigador o cómplice de un delito doloso contra la persona o los bienes del hijo de que se trata; b) abandono del hijo, dejándolo en un total estado de desprotección, aun cuando quede bajo el cuidado del otro progenitor o la guarda de un tercero; c) poner en peligro la seguridad, la salud física o psíquica del hijo; d) haberse declarado el estado de adoptabilidad del hijo. En los supuestos previstos en los incisos a), b) y c) la privación tiene efectos a partir de la sentencia que declare la privación; en el caso previsto en el inciso d) desde que se declaró el estado de adoptabilidad del hijo. ARTICULO 700 bis: Cualquiera de los progenitores queda privado de la responsabilidad parental por: a) Ser condenado como autor, coautor, instigador o cómplice del delito de homicidio agravado por el vínculo o mediando violencia de género conforme lo previsto en el artículo 80, incisos 1 y 11 del Código Penal de la Nación, en contra del otro progenitor; b) Ser condenado como autor, coautor, instigador o cómplice del delito de lesiones previstas en el artículo 91 del Código Penal, contra el otro progenitor, o contra el hijo o hija de que se trata; c) Ser condenado como autor, coautor, instigador o cómplice del delito contra la integridad sexual previsto en el artículo 119 del Código Penal de la Nación, cometido contra el hijo o hija de que se trata. La privación operará también cuando los delitos descriptos se configuren en grado de tentativa, si correspondiere. La condena penal firme produce de pleno derecho la privación de la responsabilidad parental. La sentencia definitiva debe ser comunicada al Ministerio Público a los fines de lo previsto en el artículo 703, teniéndose en cuenta la asistencia letrada establecida en el artículo 26, segundo párrafo y a la autoridad de protección de los derechos de las niñas, niños y adolescentes competente en cada jurisdicción, a efectos de que proceda en sede civil, a los efectos de este artículo. Se deberá observar lo previsto en el artículo 27 de la ley 26.061. (Artículo incorporado por art. 1° de la Ley N° 27.363 B.O. 26/6/2017. Vigencia: será aplicable a las situaciones jurídicas pendientes o en curso de ejecución.)", plainLanguageExplanation: "Establece el régimen de privación. Cualquiera de los progenitores queda privado de la responsabilidad parental por: a) ser condenado como autor, coautor, instigador o cómplice de un delito doloso contra la persona o los bienes del hijo de que se trata; b) abandono del hijo, dejándolo en un total estado de desprote", practicalEffects: ['En la práctica, este artículo rige privación. Cualquiera de los progenitores queda privado de la responsabilidad parental por: a) ser condenado como autor, coautor, instigador o cómplice de un del'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['privacinarticulo 700'], segments: [], amendments: [] },
  { id: 'ccyc-art-701', lawId: 'codigo-civil-comercial', number: '701', order: 701, title: "Rehabilitación", text: "Rehabilitación. La privación de la responsabilidad parental puede ser dejada sin efecto por el juez si los progenitores, o uno de ellos, demuestra que la restitución se justifica en beneficio e interés del hijo.", plainLanguageExplanation: "Establece el régimen de rehabilitación. La privación de la responsabilidad parental puede ser dejada sin efecto por el juez si los progenitores, o uno de ellos, demuestra que la restitución se justifica en beneficio e interés del hijo.", practicalEffects: ['En la práctica, este artículo rige rehabilitación. La privación de la responsabilidad parental puede ser dejada sin efecto por el juez si los progenitores, o uno de ellos, demuestra que la restitución'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rehabilitacinarticulo 701'], segments: [], amendments: [] },
  { id: 'ccyc-art-702', lawId: 'codigo-civil-comercial', number: '702', order: 702, title: "Suspensión del ejercicio", text: "Suspensión del ejercicio. El ejercicio de la responsabilidad parental queda suspendido mientras dure: a) La declaración de ausencia con presunción de fallecimiento; b) El plazo de la condena a reclusión y la prisión por más de tres (3) años; c) La declaración por sentencia firme de la limitación de la capacidad por razones graves de salud mental que impiden al progenitor dicho ejercicio; d) La convivencia del hijo o hija con un tercero, separado de sus progenitores por razones graves, de conformidad con lo establecido en leyes especiales; e) El procesamiento penal o acto equivalente, por los delitos mencionados en el artículo 700 bis. El auto de procesamiento debe ser comunicado al Ministerio Público a los fines de lo previsto en el artículo 703, teniéndose en cuenta la asistencia letrada establecida en el artículo 26, segundo párrafo y a la autoridad de protección de los derechos de las niñas, niños y adolescentes competente en cada jurisdicción, a efectos de que proceda en sede civil, a los fines de este artículo. Se deberá observar lo previsto en el artículo 27 de la ley 26.061. No se procederá a suspender el ejercicio de la responsabilidad parental en los términos del presente inciso en los casos del artículo 700 bis incisos a) y b), cuando en los hechos investigados o en sus antecedentes mediare violencia de género. (Artículo sustituido por art. 2° de la Ley N° 27.363 B.O. 26/6/2017. Vigencia: será aplicable a las situaciones jurídicas pendientes o en curso de ejecución.)", plainLanguageExplanation: "Establece el régimen de suspensión del ejercicio. El ejercicio de la responsabilidad parental queda suspendido mientras dure: a) La declaración de ausencia con presunción de fallecimiento; b) El plazo de la condena a reclusión y la prisión por más de tres (3) años; c) La declaración por sentencia firme de la limitación de la cap", practicalEffects: ['En la práctica, este artículo rige suspensión del ejercicio. El ejercicio de la responsabilidad parental queda suspendido mientras dure: a) La declaración de ausencia con presunción de fallecimiento; b) El plazo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['suspensin', 'ejercicio', 'articulo 702'], segments: [], amendments: [] },
  { id: 'ccyc-art-703', lawId: 'codigo-civil-comercial', number: '703', order: 703, title: "Casos de privación o suspensión de ejercicio", text: "Casos de privación o suspensión de ejercicio. Si uno de los progenitores es privado de la responsabilidad parental o suspendido en su ejercicio, el otro continúa ejerciéndola. En su defecto, se procede a iniciar los procesos correspondientes para la tutela o adopción, según la situación planteada, y siempre en beneficio e interés del niño o adolescente.", plainLanguageExplanation: "Establece el régimen de casos de privación o suspensión de ejercicio. Si uno de los progenitores es privado de la responsabilidad parental o suspendido en su ejercicio, el otro continúa ejerciéndola.", practicalEffects: ['En la práctica, este artículo rige casos de privación o suspensión de ejercicio. Si uno de los progenitores es privado de la responsabilidad parental o suspendido en su ejercicio, el otro continúa ejerciéndola.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'privacin', 'suspensin', 'ejercicio', 'articulo 703'], segments: [], amendments: [] },
  { id: 'ccyc-art-704', lawId: 'codigo-civil-comercial', number: '704', order: 704, title: "Subsistencia del deber alimentario", text: "Subsistencia del deber alimentario. Los alimentos a cargo de los progenitores subsisten durante la privación y la suspensión del ejercicio de la responsabilidad parental. TITULO VIII Procesos de familia CAPITULO 1 Disposiciones generales", plainLanguageExplanation: "Establece el régimen de subsistencia del deber alimentario. Los alimentos a cargo de los progenitores subsisten durante la privación y la suspensión del ejercicio de la responsabilidad parental.", practicalEffects: ['En la práctica, este artículo rige subsistencia del deber alimentario. Los alimentos a cargo de los progenitores subsisten durante la privación y la suspensión del ejercicio de la responsabilidad parental.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['subsistencia', 'deber', 'alimentario', 'articulo 704'], segments: [], amendments: [] },
  { id: 'ccyc-art-705', lawId: 'codigo-civil-comercial', number: '705', order: 705, title: "Ambito de aplicación", text: "Ambito de aplicación. Las disposiciones de este título son aplicables a los procesos en materia de familia, sin perjuicio de lo que la ley disponga en casos específicos.", plainLanguageExplanation: "Establece el régimen de ambito de aplicación. Las disposiciones de este título son aplicables a los procesos en materia de familia, sin perjuicio de lo que la ley disponga en casos específicos.", practicalEffects: ['En la práctica, este artículo rige ambito de aplicación. Las disposiciones de este título son aplicables a los procesos en materia de familia, sin perjuicio de lo que la ley disponga en casos específicos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ambito', 'aplicacin', 'articulo 705'], segments: [], amendments: [] },
  { id: 'ccyc-art-706', lawId: 'codigo-civil-comercial', number: '706', order: 706, title: "Principios generales de los procesos de familia", text: "Principios generales de los procesos de familia. El proceso en materia de familia debe respetar los principios de tutela judicial efectiva, inmediación, buena fe y lealtad procesal, oficiosidad, oralidad y acceso limitado al expediente. a) Las normas que rigen el procedimiento deben ser aplicadas de modo de facilitar el acceso a la justicia, especialmente tratándose de personas vulnerables, y la resolución pacífica de los conflictos. b) Los jueces ante los cuales tramitan estas causas deben ser especializados y contar con apoyo multidisciplinario. c) La decisión que se dicte en un proceso en que están involucrados niños, niñas o adolescentes, debe tener en cuenta el interés superior de esas personas.", plainLanguageExplanation: "Establece el régimen de principios generales de los procesos de familia. El proceso en materia de familia debe respetar los principios de tutela judicial efectiva, inmediación, buena fe y lealtad procesal, oficiosidad, oralidad y acceso limitado al expediente.", practicalEffects: ['En la práctica, este artículo rige principios generales de los procesos de familia. El proceso en materia de familia debe respetar los principios de tutela judicial efectiva, inmediación, buena fe y lealtad procesal, oficiosidad, oralidad y acceso limitado al expediente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['principios', 'generales', 'procesos', 'familia', 'articulo 706'], segments: [], amendments: [] },
  { id: 'ccyc-art-707', lawId: 'codigo-civil-comercial', number: '707', order: 707, title: "Participación en el proceso de personas con capacidad restringida y de niños, niñas y adolescentes", text: "Participación en el proceso de personas con capacidad restringida y de niños, niñas y adolescentes. Las personas mayores con capacidad restringida y los niños, niñas y adolescentes tienen derecho a ser oídos en todos los procesos que los afectan directamente. Su opinión debe ser tenida en cuenta y valorada según su grado de discernimiento y la cuestión debatida en el proceso.", plainLanguageExplanation: "Establece el régimen de participación en el proceso de personas con capacidad restringida y de niños, niñas y adolescentes. Las personas mayores con capacidad restringida y los niños, niñas y adolescentes tienen derecho a ser oídos en todos los procesos que los afectan directamente.", practicalEffects: ['En la práctica, este artículo rige participación en el proceso de personas con capacidad restringida y de niños, niñas y adolescentes. Las personas mayores con capacidad restringida y los niños, niñas y adolescentes tienen derecho a ser oídos en todos los procesos que los afectan directamente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['participacin', 'proceso', 'personas', 'capacidad', 'restringida', 'nios', 'nias', 'adolescentes', 'articulo 707'], segments: [], amendments: [] },
  { id: 'ccyc-art-708', lawId: 'codigo-civil-comercial', number: '708', order: 708, title: "Acceso limitado al expediente", text: "Acceso limitado al expediente. El acceso al expediente en los procesos de familia está limitado a las partes, sus representantes y letrados y a los auxiliares designados en el proceso. En caso de que las actuaciones sean ofrecidas como prueba ante otro juzgado, se debe ordenar su remisión si la finalidad de la petición lo justifica y se garantiza su reserva.", plainLanguageExplanation: "Establece el régimen de acceso limitado al expediente. El acceso al expediente en los procesos de familia está limitado a las partes, sus representantes y letrados y a los auxiliares designados en el proceso.", practicalEffects: ['En la práctica, este artículo rige acceso limitado al expediente. El acceso al expediente en los procesos de familia está limitado a las partes, sus representantes y letrados y a los auxiliares designados en el proceso.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acceso', 'limitado', 'expediente', 'articulo 708'], segments: [], amendments: [] },
  { id: 'ccyc-art-709', lawId: 'codigo-civil-comercial', number: '709', order: 709, title: "Principio de oficiosidad", text: "Principio de oficiosidad. En los procesos de familia el impulso procesal está a cargo del juez, quien puede ordenar pruebas oficiosamente. El impulso oficioso no procede en los asuntos de naturaleza exclusivamente económica en los que las partes sean personas capaces.", plainLanguageExplanation: "Establece el régimen de principio de oficiosidad. En los procesos de familia el impulso procesal está a cargo del juez, quien puede ordenar pruebas oficiosamente.", practicalEffects: ['En la práctica, este artículo rige principio de oficiosidad. En los procesos de familia el impulso procesal está a cargo del juez, quien puede ordenar pruebas oficiosamente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['principio', 'oficiosidad', 'articulo 709'], segments: [], amendments: [] },
  { id: 'ccyc-art-710', lawId: 'codigo-civil-comercial', number: '710', order: 710, title: "Principios relativos a la prueba", text: "Principios relativos a la prueba. Los procesos de familia se rigen por los principios de libertad, amplitud y flexibilidad de la prueba. La carga de la prueba recae, finalmente, en quien está en mejores condiciones de probar.", plainLanguageExplanation: "Establece el régimen de principios relativos a la prueba. Los procesos de familia se rigen por los principios de libertad, amplitud y flexibilidad de la prueba.", practicalEffects: ['En la práctica, este artículo rige principios relativos a la prueba. Los procesos de familia se rigen por los principios de libertad, amplitud y flexibilidad de la prueba.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['principios', 'relativos', 'prueba', 'articulo 710'], segments: [], amendments: [] },
  { id: 'ccyc-art-711', lawId: 'codigo-civil-comercial', number: '711', order: 711, title: "Testigos", text: "Testigos. Los parientes y allegados a las partes pueden ser ofrecidos como testigos. Sin embargo, según las circunstancias, el juez está facultado para no admitir la declaración de personas menores de edad, o de los parientes que se niegan a prestar declaración por motivos fundados. CAPITULO 2 Acciones de estado de familia", plainLanguageExplanation: "Establece el régimen de testigos. Los parientes y allegados a las partes pueden ser ofrecidos como testigos.", practicalEffects: ['En la práctica, este artículo rige testigos. Los parientes y allegados a las partes pueden ser ofrecidos como testigos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['testigosarticulo 711'], segments: [], amendments: [] },
  { id: 'ccyc-art-712', lawId: 'codigo-civil-comercial', number: '712', order: 712, title: "Irrenunciabilidad e imprescriptibilidad", text: "Irrenunciabilidad e imprescriptibilidad. Las acciones de estado de familia son irrenunciables e imprescriptibles, sin perjuicio de su extinción en la forma y en los casos que la ley establezca. Los derechos patrimoniales que son consecuencia del estado de familia están sujetos a prescripción.", plainLanguageExplanation: "Establece el régimen de irrenunciabilidad e imprescriptibilidad. Las acciones de estado de familia son irrenunciables e imprescriptibles, sin perjuicio de su extinción en la forma y en los casos que la ley establezca.", practicalEffects: ['En la práctica, este artículo rige irrenunciabilidad e imprescriptibilidad. Las acciones de estado de familia son irrenunciables e imprescriptibles, sin perjuicio de su extinción en la forma y en los casos que la ley establezca.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['irrenunciabilidad', 'imprescriptibilidad', 'articulo 712'], segments: [], amendments: [] },
  { id: 'ccyc-art-713', lawId: 'codigo-civil-comercial', number: '713', order: 713, title: "Inherencia personal", text: "Inherencia personal. Las acciones de estado de familia son de inherencia personal y no pueden ser ejercidas por vía de subrogación. Sólo se transmiten por causa de muerte en los casos en que la ley lo establece.", plainLanguageExplanation: "Establece el régimen de inherencia personal. Las acciones de estado de familia son de inherencia personal y no pueden ser ejercidas por vía de subrogación.", practicalEffects: ['En la práctica, este artículo rige inherencia personal. Las acciones de estado de familia son de inherencia personal y no pueden ser ejercidas por vía de subrogación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inherencia', 'personal', 'articulo 713'], segments: [], amendments: [] },
  { id: 'ccyc-art-714', lawId: 'codigo-civil-comercial', number: '714', order: 714, title: "Caducidad de la acción de nulidad del matrimonio por la muerte de uno de los cónyuges", text: "Caducidad de la acción de nulidad del matrimonio por la muerte de uno de los cónyuges. La acción de nulidad del matrimonio no puede ser intentada después de la muerte de uno de los cónyuges, excepto que: a) sea deducida por un cónyuge contra el siguiente matrimonio contraído por su cónyuge; si se opusiera la nulidad del matrimonio del cónyuge demandante, se debe resolver previamente esta oposición; b) sea deducida por el cónyuge supérstite de quien contrajo matrimonio mediando impedimento de ligamen y se haya celebrado ignorando la subsistencia del vínculo anterior; c) sea necesaria para determinar el derecho del demandante y la nulidad absoluta sea invocada por descendientes o ascendientes. La acción de nulidad de matrimonio deducida por el Ministerio Público sólo puede ser promovida en vida de ambos esposos.", plainLanguageExplanation: "Establece el régimen de caducidad de la acción de nulidad del matrimonio por la muerte de uno de los cónyuges. La acción de nulidad del matrimonio no puede ser intentada después de la muerte de uno de los cónyuges, excepto que: a) sea deducida por un cónyuge contra el siguiente matrimonio contraído por su cónyuge; si se opusiera la nulidad del matrimonio del cónyuge demandante, se debe re", practicalEffects: ['En la práctica, este artículo rige caducidad de la acción de nulidad del matrimonio por la muerte de uno de los cónyuges. La acción de nulidad del matrimonio no puede ser intentada después de la muerte de uno de los cónyuges, excepto que: a) sea deducida por un cónyuge co'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caducidad', 'accin', 'nulidad', 'matrimonio', 'muerte', 'cnyuges', 'articulo 714'], segments: [], amendments: [] },
  { id: 'ccyc-art-715', lawId: 'codigo-civil-comercial', number: '715', order: 715, title: "Sentencia de nulidad", text: "Sentencia de nulidad. Ningún matrimonio puede ser tenido por nulo sin sentencia que lo anule, dictada en proceso promovido por parte legitimada para hacerlo. CAPITULO 3 Reglas de competencia", plainLanguageExplanation: "Establece el régimen de sentencia de nulidad. Ningún matrimonio puede ser tenido por nulo sin sentencia que lo anule, dictada en proceso promovido por parte legitimada para hacerlo.", practicalEffects: ['En la práctica, este artículo rige sentencia de nulidad. Ningún matrimonio puede ser tenido por nulo sin sentencia que lo anule, dictada en proceso promovido por parte legitimada para hacerlo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sentencia', 'nulidad', 'articulo 715'], segments: [], amendments: [] },
  { id: 'ccyc-art-716', lawId: 'codigo-civil-comercial', number: '716', order: 716, title: "Procesos relativos a los derechos de niños, niñas y adolescentes", text: "Procesos relativos a los derechos de niños, niñas y adolescentes. En los procesos referidos a responsabilidad parental, guarda, cuidado, régimen de comunicación, alimentos, adopción y otros que deciden en forma principal o que modifican lo resuelto en otra jurisdicción del territorio nacional sobre derechos de niños, niñas y adolescentes, es competente el juez del lugar donde la persona menor de edad tiene su centro de vida.", plainLanguageExplanation: "Establece el régimen de procesos relativos a los derechos de niños, niñas y adolescentes. En los procesos referidos a responsabilidad parental, guarda, cuidado, régimen de comunicación, alimentos, adopción y otros que deciden en forma principal o que modifican lo resuelto en otra jurisdicción del territorio nacional sobre derechos de niños, niñas y adolescentes, es co", practicalEffects: ['En la práctica, este artículo rige procesos relativos a los derechos de niños, niñas y adolescentes. En los procesos referidos a responsabilidad parental, guarda, cuidado, régimen de comunicación, alimentos, adopción y otros que deciden en forma princ'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['procesos', 'relativos', 'derechos', 'nios', 'nias', 'adolescentes', 'articulo 716'], segments: [], amendments: [] },
  { id: 'ccyc-art-717', lawId: 'codigo-civil-comercial', number: '717', order: 717, title: "Procesos de divorcio y nulidad del matrimonio", text: "Procesos de divorcio y nulidad del matrimonio. En las acciones de divorcio o nulidad, las conexas con ellas y las que versan sobre los efectos de la sentencia, es competente el juez del último domicilio conyugal o el del demandado a elección del actor, o el de cualquiera de los cónyuges si la presentación es conjunta. Si se ha declarado el concurso o la quiebra de uno de los cónyuges, en la liquidación del régimen patrimonial del matrimonio es competente el juez del proceso colectivo.", plainLanguageExplanation: "Establece el régimen de procesos de divorcio y nulidad del matrimonio. En las acciones de divorcio o nulidad, las conexas con ellas y las que versan sobre los efectos de la sentencia, es competente el juez del último domicilio conyugal o el del demandado a elección del actor, o el de cualquiera de los cónyuges si la presentación es conjunta.", practicalEffects: ['En la práctica, este artículo rige procesos de divorcio y nulidad del matrimonio. En las acciones de divorcio o nulidad, las conexas con ellas y las que versan sobre los efectos de la sentencia, es competente el juez del último domi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['procesos', 'divorcio', 'nulidad', 'matrimonio', 'articulo 717'], segments: [], amendments: [] },
  { id: 'ccyc-art-718', lawId: 'codigo-civil-comercial', number: '718', order: 718, title: "Uniones convivenciales", text: "Uniones convivenciales. En los conflictos derivados de las uniones convivenciales, es competente el juez del último domicilio convivencial o el del demandado a elección del actor,", plainLanguageExplanation: "Establece el régimen de uniones convivenciales. En los conflictos derivados de las uniones convivenciales, es competente el juez del último domicilio convivencial o el del demandado a elección del actor,", practicalEffects: ['En la práctica, este artículo rige uniones convivenciales. En los conflictos derivados de las uniones convivenciales, es competente el juez del último domicilio convivencial o el del demandado a elección del a'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['uniones', 'convivenciales', 'articulo 718'], segments: [], amendments: [] },
  { id: 'ccyc-art-719', lawId: 'codigo-civil-comercial', number: '719', order: 719, title: "Alimentos y pensiones compensatorias entre cónyuges o convivientes", text: "Alimentos y pensiones compensatorias entre cónyuges o convivientes. En las acciones por alimentos o por pensiones compensatorias entre cónyuges o convivientes es competente el juez del último domicilio conyugal o convivencial, o el del domicilio del beneficiario, o el del demandado, o aquel donde deba ser cumplida la obligación alimentaria, a elección del actor.", plainLanguageExplanation: "Establece el régimen de alimentos y pensiones compensatorias entre cónyuges o convivientes. En las acciones por alimentos o por pensiones compensatorias entre cónyuges o convivientes es competente el juez del último domicilio conyugal o convivencial, o el del domicilio del beneficiario, o el del demandado, o aquel donde deba ser cumplida la obligación alimentaria, a ele", practicalEffects: ['En la práctica, este artículo rige alimentos y pensiones compensatorias entre cónyuges o convivientes. En las acciones por alimentos o por pensiones compensatorias entre cónyuges o convivientes es competente el juez del último domicilio conyugal o convi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['alimentos', 'pensiones', 'compensatorias', 'entre', 'cnyuges', 'convivientes', 'articulo 719'], segments: [], amendments: [] },
  { id: 'ccyc-art-720', lawId: 'codigo-civil-comercial', number: '720', order: 720, title: "Acción de filiación", text: "Acción de filiación. En la acción de filiación, excepto que el actor sea persona menor de edad o con capacidad restringida, es competente el juez del domicilio del demandado. CAPITULO 4 Medidas provisionales", plainLanguageExplanation: "Establece el régimen de acción de filiación. En la acción de filiación, excepto que el actor sea persona menor de edad o con capacidad restringida, es competente el juez del domicilio del demandado.", practicalEffects: ['En la práctica, este artículo rige acción de filiación. En la acción de filiación, excepto que el actor sea persona menor de edad o con capacidad restringida, es competente el juez del domicilio del demandado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'filiacin', 'articulo 720'], segments: [], amendments: [] },
  { id: 'ccyc-art-721', lawId: 'codigo-civil-comercial', number: '721', order: 721, title: "Medidas provisionales relativas a las personas en el divorcio y en la nulidad de matrimonio", text: "Medidas provisionales relativas a las personas en el divorcio y en la nulidad de matrimonio. Deducida la acción de nulidad o de divorcio, o antes en caso de urgencia, el juez puede tomar las medidas provisionales necesarias para regular las relaciones personales entre los cónyuges y los hijos durante el proceso. Puede especialmente: a) determinar, teniendo en cuenta el interés familiar, cuál de los cónyuges ha de continuar en el uso de la vivienda familiar y, previo inventario, qué bienes retira el cónyuge que deja el inmueble; b) si corresponde, establecer la renta por el uso exclusivo de la vivienda por parte de uno de los cónyuges; c) ordenar la entrega de los objetos de uso personal; d) disponer un régimen de alimentos y ejercicio y cuidado de los hijos conforme con lo establecido en el Título VII de este Libro; e) determinar los alimentos que solicite el cónyuge teniendo en cuenta las pautas establecidas en el artículo 433.", plainLanguageExplanation: "Establece el régimen de medidas provisionales relativas a las personas en el divorcio y en la nulidad de matrimonio. Deducida la acción de nulidad o de divorcio, o antes en caso de urgencia, el juez puede tomar las medidas provisionales necesarias para regular las relaciones personales entre los cónyuges y los hijos durante el proceso.", practicalEffects: ['En la práctica, este artículo rige medidas provisionales relativas a las personas en el divorcio y en la nulidad de matrimonio. Deducida la acción de nulidad o de divorcio, o antes en caso de urgencia, el juez puede tomar las medidas provisionales necesarias para regular las re'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medidas', 'provisionales', 'relativas', 'personas', 'divorcio', 'nulidad', 'matrimonio', 'articulo 721'], segments: [], amendments: [] },
  { id: 'ccyc-art-722', lawId: 'codigo-civil-comercial', number: '722', order: 722, title: "Medidas provisionales relativas a los bienes en el divorcio y en la nulidad de matrimonio", text: "Medidas provisionales relativas a los bienes en el divorcio y en la nulidad de matrimonio. Deducida la acción de nulidad o de divorcio, o antes en caso de urgencia, a pedido de parte, el juez debe disponer las medidas de seguridad para evitar que la administración o disposición de los bienes por uno de los cónyuges pueda poner en peligro, hacer inciertos o defraudar los derechos patrimoniales del otro, cualquiera sea el régimen patrimonial matrimonial. También puede ordenar las medidas tendientes a individualizar la existencia de bienes o derechos de los que los cónyuges fuesen titulares. La decisión que acoge estas medidas debe establecer un plazo de duración", plainLanguageExplanation: "Establece el régimen de medidas provisionales relativas a los bienes en el divorcio y en la nulidad de matrimonio. Deducida la acción de nulidad o de divorcio, o antes en caso de urgencia, a pedido de parte, el juez debe disponer las medidas de seguridad para evitar que la administración o disposición de los bienes por uno de los cónyuges pueda poner en peligro, hacer inciertos o defraudar lo", practicalEffects: ['En la práctica, este artículo rige medidas provisionales relativas a los bienes en el divorcio y en la nulidad de matrimonio. Deducida la acción de nulidad o de divorcio, o antes en caso de urgencia, a pedido de parte, el juez debe disponer las medidas de seguridad para evita'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medidas', 'provisionales', 'relativas', 'bienes', 'divorcio', 'nulidad', 'matrimonio', 'articulo 722'], segments: [], amendments: [] },
  { id: 'ccyc-art-723', lawId: 'codigo-civil-comercial', number: '723', order: 723, title: "Ambito de aplicación", text: "Ambito de aplicación. Los artículos 721 y 722 son aplicables a las uniones convivenciales, en cuanto sea pertinente. LIBRO TERCERO DERECHOS PERSONALES TITULO I Obligaciones en general CAPITULO 1 Disposiciones generales", plainLanguageExplanation: "Establece el régimen de ambito de aplicación. Los artículos 721 y 722 son aplicables a las uniones convivenciales, en cuanto sea pertinente.", practicalEffects: ['En la práctica, este artículo rige ambito de aplicación. Los artículos 721 y 722 son aplicables a las uniones convivenciales, en cuanto sea pertinente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ambito', 'aplicacin', 'articulo 723'], segments: [], amendments: [] },
];
